import javafx.animation.*;
import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.VBox;
import javafx.scene.paint.Color;
import javafx.scene.shape.Circle;
import javafx.scene.shape.Rectangle;
import javafx.stage.Stage;
import javafx.util.Duration;

public class AnimationExample extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(20);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        Label title = new Label("JavaFX Animation");
        title.setStyle("-fx-font-size: 20px; -fx-font-weight: bold;");
        root.getChildren().add(title);

        // 1. TranslateTransition (move)
        System.out.println("=== TranslateTransition ===");
        Rectangle rect = new Rectangle(60, 40, Color.BLUE);
        rect.setArcWidth(10);
        rect.setArcHeight(10);

        Button moveBtn = new Button("Move Rectangle");

        TranslateTransition translate = new TranslateTransition(Duration.seconds(2), rect);
        translate.setFromX(0);
        translate.setToX(200);
        translate.setCycleCount(TranslateTransition.INDEFINITE);
        translate.setAutoReverse(true);

        moveBtn.setOnAction(e -> {
            if (translate.getStatus() == Animation.Status.RUNNING) {
                translate.pause();
                moveBtn.setText("Resume");
            } else if (translate.getStatus() == Animation.Status.PAUSED) {
                translate.play();
                moveBtn.setText("Pause");
            } else {
                translate.play();
                moveBtn.setText("Pause");
            }
        });

        // 2. FadeTransition (fade in/out)
        System.out.println("=== FadeTransition ===");
        Circle circle = new Circle(30, Color.RED);

        Button fadeBtn = new Button("Fade Circle");

        FadeTransition fade = new FadeTransition(Duration.seconds(1.5), circle);
        fade.setFromValue(1.0);
        fade.setToValue(0.1);
        fade.setCycleCount(FadeTransition.INDEFINITE);
        fade.setAutoReverse(true);

        fadeBtn.setOnAction(e -> {
            if (fade.getStatus() == Animation.Status.RUNNING) {
                fade.pause();
                fadeBtn.setText("Resume Fade");
            } else if (fade.getStatus() == Animation.Status.PAUSED) {
                fade.play();
                fadeBtn.setText("Pause Fade");
            } else {
                fade.play();
                fadeBtn.setText("Pause Fade");
            }
        });

        // 3. RotateTransition (rotate)
        System.out.println("=== RotateTransition ===");
        Rectangle square = new Rectangle(50, 50, Color.GREEN);

        Button rotateBtn = new Button("Rotate Square");

        RotateTransition rotate = new RotateTransition(Duration.seconds(2), square);
        rotate.setFromAngle(0);
        rotate.setToAngle(360);
        rotate.setCycleCount(RotateTransition.INDEFINITE);

        rotateBtn.setOnAction(e -> {
            if (rotate.getStatus() == Animation.Status.RUNNING) {
                rotate.pause();
                rotateBtn.setText("Resume Rotate");
            } else if (rotate.getStatus() == Animation.Status.PAUSED) {
                rotate.play();
                rotateBtn.setText("Pause Rotate");
            } else {
                rotate.play();
                rotateBtn.setText("Pause Rotate");
            }
        });

        // 4. ScaleTransition (scale)
        System.out.println("=== ScaleTransition ===");
        Circle scaleCircle = new Circle(25, Color.PURPLE);

        Button scaleBtn = new Button("Scale Circle");

        ScaleTransition scale = new ScaleTransition(Duration.seconds(1.5), scaleCircle);
        scale.setFromX(1.0);
        scale.setToX(2.0);
        scale.setFromY(1.0);
        scale.setToY(2.0);
        scale.setCycleCount(ScaleTransition.INDEFINITE);
        scale.setAutoReverse(true);

        scaleBtn.setOnAction(e -> {
            if (scale.getStatus() == Animation.Status.RUNNING) {
                scale.pause();
                scaleBtn.setText("Resume Scale");
            } else if (scale.getStatus() == Animation.Status.PAUSED) {
                scale.play();
                scaleBtn.setText("Pause Scale");
            } else {
                scale.play();
                scaleBtn.setText("Pause Scale");
            }
        });

        // 5. Timeline (custom animation)
        System.out.println("=== Timeline ===");
        Rectangle timeRect = new Rectangle(40, 40, Color.ORANGE);
        Label timeLabel = new Label("Timeline: 0");

        Button timelineBtn = new Button("Start Timeline");

        Timeline timeline = new Timeline();
        timeline.setCycleCount(Timeline.INDEFINITE);

        KeyFrame keyFrame = new KeyFrame(Duration.seconds(0.1), e -> {
            // Update label
            String text = timeLabel.getText();
            int value = Integer.parseInt(text.substring(text.indexOf(":") + 1).trim());
            value++;
            timeLabel.setText("Timeline: " + value);

            // Change color
            int r = (value * 10) % 255;
            int g = (value * 5) % 255;
            int b = (value * 3) % 255;
            timeRect.setFill(Color.rgb(r, g, b));
        });

        timeline.getKeyFrames().add(keyFrame);

        timelineBtn.setOnAction(e -> {
            if (timeline.getStatus() == Animation.Status.RUNNING) {
                timeline.pause();
                timelineBtn.setText("Resume Timeline");
            } else if (timeline.getStatus() == Animation.Status.PAUSED) {
                timeline.play();
                timelineBtn.setText("Pause Timeline");
            } else {
                timeline.play();
                timelineBtn.setText("Pause Timeline");
            }
        });

        // 6. SequentialTransition (multiple animations in sequence)
        System.out.println("=== SequentialTransition ===");
        Rectangle seqRect = new Rectangle(50, 50, Color.PINK);

        Button seqBtn = new Button("Run Sequence");

        // Move left and right
        TranslateTransition move1 = new TranslateTransition(Duration.seconds(1), seqRect);
        move1.setFromX(0);
        move1.setToX(150);

        TranslateTransition move2 = new TranslateTransition(Duration.seconds(1), seqRect);
        move2.setFromX(150);
        move2.setToX(0);

        // Fade
        FadeTransition seqFade = new FadeTransition(Duration.seconds(0.5), seqRect);
        seqFade.setFromValue(1.0);
        seqFade.setToValue(0.3);
        seqFade.setAutoReverse(true);

        SequentialTransition seqAnimation = new SequentialTransition(seqRect, move1, seqFade, move2);
        seqAnimation.setCycleCount(SequentialTransition.INDEFINITE);

        seqBtn.setOnAction(e -> {
            if (seqAnimation.getStatus() == Animation.Status.RUNNING) {
                seqAnimation.pause();
                seqBtn.setText("Resume Sequence");
            } else if (seqAnimation.getStatus() == Animation.Status.PAUSED) {
                seqAnimation.play();
                seqBtn.setText("Pause Sequence");
            } else {
                seqAnimation.play();
                seqBtn.setText("Pause Sequence");
            }
        });

        // 7. Stop all button
        Button stopAllBtn = new Button("Stop All");
        stopAllBtn.setStyle("-fx-background-color: #e74c3c; -fx-text-fill: white;");
        stopAllBtn.setOnAction(e -> {
            translate.stop();
            fade.stop();
            rotate.stop();
            scale.stop();
            timeline.stop();
            seqAnimation.stop();

            moveBtn.setText("Move");
            fadeBtn.setText("Fade");
            rotateBtn.setText("Rotate");
            scaleBtn.setText("Scale");
            timelineBtn.setText("Start Timeline");
            seqBtn.setText("Run Sequence");

            timeLabel.setText("Timeline: 0");
            timeRect.setFill(Color.ORANGE);
        });

        root.getChildren().addAll(
            rect,
            moveBtn,
            circle,
            fadeBtn,
            square,
            rotateBtn,
            scaleCircle,
            scaleBtn,
            timeRect,
            timeLabel,
            timelineBtn,
            seqRect,
            seqBtn,
            stopAllBtn
        );

        Scene scene = new Scene(root, 500, 800);

        primaryStage.setTitle("JavaFX Animation");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

