import javafx.animation.TranslateTransition;
import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.layout.HBox;
import javafx.scene.layout.VBox;
import javafx.scene.paint.Color;
import javafx.scene.shape.Circle;
import javafx.stage.Stage;
import javafx.util.Duration;

public class AnimationPractice extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(20);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        Circle circle = new Circle(30, Color.BLUE);

        TranslateTransition tt = new TranslateTransition(Duration.seconds(2), circle);
        tt.setFromX(0);
        tt.setToX(300);
        tt.setCycleCount(TranslateTransition.INDEFINITE);
        tt.setAutoReverse(true);

        Button startBtn = new Button("Start Animation");
        startBtn.setOnAction(e -> tt.play());

        Button stopBtn = new Button("Stop Animation");
        stopBtn.setOnAction(e -> {
            tt.stop();
            // Reset position (optional)
            circle.setTranslateX(0);
        });

        HBox controls = new HBox(10);
        controls.setAlignment(Pos.CENTER);
        controls.getChildren().addAll(startBtn, stopBtn);

        root.getChildren().addAll(circle, controls);

        Scene scene = new Scene(root, 500, 200);
        primaryStage.setTitle("Animation Practice");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}
